                            tables: [{"after": "12", "html": "<div style=\"font-weight:700;color:#1e3a5f;font-size:12px;margin-bottom:6px;text-align:left;\">Tableau 27 : Crédits d’innovation pour l’énergie non réglementée neutre en carbone et carbone négatif</div><table style=\"width:100%;border-collapse:collapse;font-size:11.5px;line-height:1.3;\"><thead><tr><th style=\"padding:6px 8px;text-align:left;border:1px solid #0d9488;background:#0f766e;color:white;font-size:11px;\">Crédits d’innovation</th><th style=\"padding:6px 8px;text-align:left;border:1px solid #0d9488;background:#0f766e;color:white;font-size:11px;\">% de consommation énergétique opérationnelle provenant de sources neutres en carbone</th></tr></thead><tbody><tr><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;background:#f0fdfa;vertical-align:top;\">3</td><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;background:#f0fdfa;vertical-align:top;\">≥ 20</td></tr><tr><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;vertical-align:top;\">4</td><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;vertical-align:top;\">≥ 50</td></tr><tr><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;background:#f0fdfa;vertical-align:top;\">5</td><td style=\"padding:5px 8px;border:1px solid #e2e8f0;font-size:11px;background:#f0fdfa;vertical-align:top;\">≥ 100</td></tr></tbody></table>"}]
